    aOptions: AndroidOptions(
      encryptedSharedPreferences: true,
    ),
    iOptions: IOSOptions(
      accessibility: KeychainAccessibility.first_unlock_this_device,
    ),
  );

  static const String _accessTokenKey = 'secure_access_token';
  static const String _refreshTokenKey = 'secure_refresh_token';
  static const String _tokenExpiryKey = 'secure_token_expiry';
  static const String _encryptionKeyKey = 'secure_encryption_key';

  // Access Token
  Future<void> saveAccessToken(String token) async {
    await _secureStorage.write(key: _accessTokenKey, value: token);
  }

  Future<String?> getAccessToken() async {
    return await _secureStorage.read(key: _accessTokenKey);
  }

  Future<void> deleteAccessToken() async {
    await _secureStorage.delete(key: _accessTokenKey);
  }

  // Refresh Token
  Future<void> saveRefreshToken(String token) async {
    await _secureStorage.write(key: _refreshTokenKey, value: token);
  }

  Future<String?> getRefreshToken() async {
    return await _secureStorage.read(key: _refreshTokenKey);
  }

  Future<void> deleteRefreshToken() async {
    await _secureStorage.delete(key: _refreshTokenKey);
  }

  // Token Expiry
  Future<void> saveTokenExpiry(DateTime expiry) async {
    await _secureStorage.write(
        key: _tokenExpiryKey, value: expiry.toIso8601String());
  }

  Future<DateTime?> getTokenExpiry() async {
    final value = await _secureStorage.read(key: _tokenExpiryKey);
    return value != null ? DateTime.tryParse(value) : null;
  }

  Future<bool> isTokenExpired() async {
    final expiry = await getTokenExpiry();
    if (expiry == null) return true;
    return DateTime.now().isAfter(expiry);
  }

  // Save all auth tokens at once
  Future<void> saveAuthTokens({
    required String accessToken,
    required String refreshToken,
    required DateTime expiry,
  }) async {
    await Future.wait([
      saveAccessToken(accessToken),
      saveRefreshToken(refreshToken),
      saveTokenExpiry(expiry),
    ]);
  }

  // Clear all secure data
  Future<void> clearAll() async {
    await _secureStorage.deleteAll();
  }

  // Store arbitrary secure data
  Future<void> saveSecureData(String key, String value) async {
    final sanitizedKey = _sanitizeKey(key);
    await _secureStorage.write(key: sanitizedKey, value: value);
  }

  Future<String?> getSecureData(String key) async {
    final sanitizedKey = _sanitizeKey(key);
    return await _secureStorage.read(key: sanitizedKey);
  }

  Future<void> deleteSecureData(String key) async {
    final sanitizedKey = _sanitizeKey(key);
    await _secureStorage.delete(key: sanitizedKey);
  }

  String _sanitizeKey(String key) {
    return key.replaceAll(RegExp(r'[^a-zA-Z0-9_]'), '_');
  }
}

