// Cache Manager
class CacheManager {
  static SharedPreferences? _prefs;
  static const String _cachePrefix = 'cache_';
  static const String _cacheIndexKey = 'cache_index';
  static const int _maxCacheEntries = 100;

  Future<SharedPreferences> get prefs async {
    _prefs ??= await SharedPreferences.getInstance();
    return _prefs!;
  }

  String _cacheKey(String key) => '$_cachePrefix$key';

  Future<void> put(String key, String data,
      {Duration ttl = const Duration(hours: 1)}) async {
    final checksum = sha256.convert(utf8.encode(data)).toString();
    final cached = CachedContent(
      key: key,
      data: data,
      ttl: ttl,
      checksum: checksum,
    );

    final p = await prefs;
    await p.setString(_cacheKey(key), jsonEncode(cached.toJson()));
    await _addToIndex(key);
    await _evictIfNeeded();
  }

  Future<String?> get(String key) async {
    final p = await prefs;
    final raw = p.getString(_cacheKey(key));
    if (raw == null) return null;

    try {
      final cached = CachedContent.fromJson(jsonDecode(raw));

      if (cached.isExpired) {
        await remove(key);
        return null;
      }

      if (!cached.verifyIntegrity()) {
        debugPrint('Cache integrity check failed for key: $key');
        await remove(key);
        return null;
      }

      return cached.data;
    } catch (e) {
      debugPrint('Error reading cache for key $key: $e');
      await remove(key);
      return null;
    }
  }

  Future<void> putJson(String key, Map<String, dynamic> data,
      {Duration ttl = const Duration(hours: 1)}) async {
    await put(key, jsonEncode(data), ttl: ttl);
  }

  Future<Map<String, dynamic>?> getJson(String key) async {
    final data = await get(key);
    if (data == null) return null;
    try {
      return jsonDecode(data) as Map<String, dynamic>;
    } catch (e) {
      debugPrint('Error parsing cached JSON for key $key: $e');
      return null;
    }
  }

  Future<void> remove(String key) async {
    final p = await prefs;
    await p.remove(_cacheKey(key));
    await _removeFromIndex(key);
  }

  Future<bool> has(String key) async {
    final data = await get(key);
    return data != null;
  }

  Future<void> clearAll() async {
    final index = await _getIndex();
    final p = await prefs;
    for (final key in index) {
      await p.remove(_cacheKey(key));
    }
    await p.remove(_cacheIndexKey);
  }

  Future<void> clearExpired() async {
    final index = await _getIndex();
    final p = await prefs;
    final keysToRemove = <String>[];

    for (final key in index) {
      final raw = p.getString(_cacheKey(key));
      if (raw == null) {
        keysToRemove.add(key);
        continue;
      }
      try {
        final cached = CachedContent.fromJson(jsonDecode(raw));
        if (cached.isExpired) {
          keysToRemove.add(key);
        }
      } catch (_) {
        keysToRemove.add(key);
      }
    }

    for (final key in keysToRemove) {
      await p.remove(_cacheKey(key));
    }

    final updatedIndex = index.where((k) => !keysToRemove.contains(k)).toList();
    await p.setStringList(_cacheIndexKey, updatedIndex);
  }

  Future<List<String>> _getIndex() async {
    final p = await prefs;
    return p.getStringList(_cacheIndexKey) ?? [];
  }

  Future<void> _addToIndex(String key) async {
    final index = await _getIndex();
    if (!index.contains(key)) {
      index.add(key);
      final p = await prefs;
      await p.setStringList(_cacheIndexKey, index);
    }
  }

  Future<void> _removeFromIndex(String key) async {
    final index = await _getIndex();
    index.remove(key);
    final p = await prefs;
    await p.setStringList(_cacheIndexKey, index);
  }

  Future<void> _evictIfNeeded() async {
    final index = await _getIndex();
    if (index.length <= _maxCacheEntries) return;

    // Evict oldest entries first (FIFO)
    final p = await prefs;
    final entriesToRemove = index.length - _maxCacheEntries;
    final keysToRemove = index.take(entriesToRemove).toList();

    for (final key in keysToRemove) {
      await p.remove(_cacheKey(key));
    }

    final updatedIndex = index.skip(entriesToRemove).toList();
    await p.setStringList(_cacheIndexKey, updatedIndex);
  }

  Future<int> getCacheSize() async {
    final index = await _getIndex();
    return index.length;
  }
}

