// Main Local Storage Manager - Facade
class LocalStorageManager {
  static LocalStorageManager? _instance;

  final SecureStorageManager secureStorage;
  final PreferencesManager preferences;
  final CacheManager cache;
  final UserProfileManager userProfile;
  final AppConfigManager appConfig;

  LocalStorageManager._({
    required this.secureStorage,
    required this.preferences,
    required this.cache,
    required this.userProfile,
    required this.appConfig,
  });

  factory LocalStorageManager() {
    _instance ??= LocalStorageManager._(
      secureStorage: SecureStorageManager(),
      preferences: PreferencesManager(),
      cache: CacheManager(),
      userProfile: UserProfileManager(),
      appConfig: AppConfigManager(),
    );
    return _instance!;
  }

  /// Initialize the storage manager - call this early in app startup
  Future<void> initialize() async {
    // Pre-warm SharedPreferences
    await SharedPreferences.getInstance();
    // Clean up expired cache entries
    await cache.clearExpired();
    debugPrint('LocalStorageManager initialized');
  }

  /// Save complete authentication session
  Future<void> saveAuthSession({
    required String accessToken,
    required String refreshToken,
    required DateTime tokenExpiry,
    required UserProfile profile,
  }) async {
    await Future.wait([
      secureStorage.saveAuthTokens(
        accessToken: accessToken,
        refreshToken: refreshToken,
        expiry: tokenExpiry,
      ),
      userProfile.saveProfile(profile),
    ]);
  }

  /// Check if user is authenticated with valid token
  Future<bool> isAuthenticated() async {
    final token = await secureStorage.getAccessToken();
    if (token == null) return false;
    final isExpired = await secureStorage.isTokenExpired();
    return !isExpired;
  }

  /// Check if refresh token is available (for silent re-auth)
  Future<bool> canRefreshAuth() async {
    final refreshToken = await secureStorage.getRefreshToken();
    return refreshToken != null;
  }

  /// Clear all user-related data (logout)
  Future<void> logout() async {
    await Future.wait([
      secureStorage.clearAll(),
      userProfile.clearProfile(),
      cache.clearAll(),
    ]);
    // Keep preferences (theme, locale, etc.)
    debugPrint('User logged out, storage cleared');
  }

  /// Clear absolutely everything
  Future<void> clearAllData() async {
    await Future.wait([
      secureStorage.clearAll(),
      preferences.clearAll(),
      cache.clearAll(),
      userProfile.clearProfile(),
      appConfig.clearConfig(),
    ]);
    debugPrint('All local storage cleared');
  }

  /// Get a quick summary of stored data for debugging (no sensitive data)
  Future<Map<String, dynamic>> getStorageSummary() async {
    final hasToken = (await secureStorage.getAccessToken()) != null;
    final hasRefresh = (await secureStorage.getRefreshToken()) != null;
    final isExpired = await secureStorage.isTokenExpired();
    final hasProfile = await userProfile.hasProfile();
    final configStale = await appConfig.isConfigStale();
    final cacheSize = await cache.getCacheSize();
    final theme = await preferences.getThemeMode();
    final locale = await preferences.getLocale();

    return {
      'hasAccessToken': hasToken,
      'hasRefreshToken': hasRefresh,
      'isTokenExpired': isExpired,
      'hasUserProfile': hasProfile,
      'isConfigStale': configStale,
      'cacheEntries': cacheSize,
      'theme': theme,
      'locale': locale,
    };
  }
}

